<script setup lang="ts">import { onMounted,reactive,ref } from 'vue';import { adminApi } from '@/api';import { ElMessage,ElMessageBox } from 'element-plus';import type { User } from '@/types';const list=ref<User[]>([]),dialog=ref(false),editing=ref<number>(),form=reactive({username:'',nickname:'',password:'123456',status:'ENABLED',roles:['USER']});onMounted(load);async function load(){list.value=await adminApi.users()}function open(item?:User){editing.value=item?.id;Object.assign(form,item?{...item,password:'',roles:[...item.roles]}:{username:'',nickname:'',password:'123456',status:'ENABLED',roles:['USER']});dialog.value=true}async function save(){if(editing.value)await adminApi.updateUser(editing.value,{nickname:form.nickname,status:form.status,roles:form.roles});else await adminApi.createUser(form);dialog.value=false;ElMessage.success('保存成功');load()}async function reset(id:number){await ElMessageBox.confirm('密码将重置为 123456，确认继续？','重置密码',{type:'warning'});await adminApi.resetPassword(id);ElMessage.success('密码已重置')}</script>
<template><div class="page"><header class="page-head"><div><span class="eyebrow">USER ADMIN</span><h1>用户管理</h1><p>维护账号、角色和启停状态。</p></div><el-button type="primary" @click="open()">新增用户</el-button></header><el-table :data="list" class="glass-table"><el-table-column prop="username" label="账号"/><el-table-column prop="nickname" label="昵称"/><el-table-column label="角色"><template #default="{row}"><el-tag v-for="role in row.roles" :key="role" class="role-tag">{{role}}</el-tag></template></el-table-column><el-table-column label="状态" width="120"><template #default="{row}"><el-tag :type="row.status==='ENABLED'?'success':'info'">{{row.status}}</el-tag></template></el-table-column><el-table-column label="操作" width="220"><template #default="{row}"><el-button text type="primary" @click="open(row)">编辑</el-button><el-button text @click="reset(row.id)">重置密码</el-button></template></el-table-column></el-table><el-dialog v-model="dialog" :title="editing?'编辑用户':'新增用户'" width="500"><el-form :model="form" label-position="top"><el-form-item label="账号"><el-input v-model="form.username" :disabled="!!editing"/></el-form-item><el-form-item label="昵称"><el-input v-model="form.nickname"/></el-form-item><el-form-item v-if="!editing" label="初始密码"><el-input v-model="form.password" type="password" show-password/></el-form-item><el-form-item label="状态"><el-radio-group v-model="form.status"><el-radio-button value="ENABLED">启用</el-radio-button><el-radio-button value="DISABLED">停用</el-radio-button></el-radio-group></el-form-item><el-form-item label="角色"><el-checkbox-group v-model="form.roles"><el-checkbox value="USER">普通用户</el-checkbox><el-checkbox value="ADMIN">管理员</el-checkbox></el-checkbox-group></el-form-item></el-form><template #footer><el-button @click="dialog=false">取消</el-button><el-button type="primary" @click="save">保存</el-button></template></el-dialog></div></template>
